// Карточный каталог: slug → цена + название.
// Цены ДОЛЖНЫ совпадать с _data/guides.yml на сайте.
const CATALOG = {
  'relocation-english':   { title: 'Английский для релокации',                price: 2990 },
  'english-for-parents':  { title: 'Английский для родителей',                price: 2990 },
  'medical-english':      { title: 'Английский для медиков',                  price: 4990 },
  'it-interview-english': { title: 'English for Tech Interviews',             price: 2990 },
  'ai-first-english':     { title: 'AI-first English for Tech Stars',         price: 2490 },
  'legal-english':        { title: 'Legal English: Contracts & Compliance',   price: 5990 },
  'logistics-english':    { title: 'Logistic English',                        price: 3490 },
  'leadership-english':   { title: 'The language of Power — English for Leaders', price: 5490 }
};

// Куда возвращать после оплаты. Поменяй на боевой домен после переезда с GitHub Pages.
const RETURN_URL = 'https://nilolafeo-bit.github.io/special_english/thank-you/';

// --- Валидация входа: жёсткие whitelist-проверки, чтобы пользователь
//     не мог инжектнуть произвольные поля в JSON-тело запроса в ЮKassa. ---
const body = (items[0].json && items[0].json.body) || items[0].json || {};
const slug = (body.guide_slug || '').toString();
const email = (body.email || '').toString().trim();
const idempotenceKey = (body.idempotence_key || '').toString().trim();
const sourceUrl = (body.source_url || '').toString().trim();

// 1) slug — только из каталога
if (!slug || !Object.prototype.hasOwnProperty.call(CATALOG, slug)) {
  throw new Error('Unknown guide_slug: ' + slug);
}

// 2) email — узкий безопасный набор символов, без кавычек/слэшей/скобок
const EMAIL_RE = /^[A-Za-z0-9._%+\-]+@[A-Za-z0-9.\-]+\.[A-Za-z]{2,}$/;
if (!email || email.length > 254 || !EMAIL_RE.test(email)) {
  throw new Error('Invalid email');
}

// 3) idempotence_key — UUID-подобная строка
const IDEMP_RE = /^[A-Za-z0-9._\-]{8,128}$/;
if (!IDEMP_RE.test(idempotenceKey)) {
  throw new Error('Invalid idempotence_key');
}

// 4) source_url — http(s), без кавычек/обратных слэшей, ограничение длины
let safeSourceUrl = '';
if (sourceUrl) {
  if (sourceUrl.length > 2048 || /["\\]/.test(sourceUrl) || !/^https?:\/\//.test(sourceUrl)) {
    throw new Error('Invalid source_url');
  }
  safeSourceUrl = sourceUrl;
}

const product = CATALOG[slug];
const priceValue = product.price.toFixed(2); // 'NNNN.00'

// Собираем тело как объект, а в HTTP-ноде делаем JSON.stringify($json.payment_body).
// Это гарантирует, что любые пользовательские значения экранируются как JSON-строки,
// и не позволяет «вылезти» из строки и подменить, например, поле amount.
const paymentBody = {
  amount: { value: priceValue, currency: 'RUB' },
  capture: true,
  confirmation: { type: 'redirect', return_url: RETURN_URL },
  description: 'Гайд: ' + product.title,
  metadata: {
    guide_slug: slug,
    email,
    source_url: safeSourceUrl
  },
  receipt: {
    customer: { email },
    items: [
      {
        description: product.title,
        quantity: '1.00',
        amount: { value: priceValue, currency: 'RUB' },
        vat_code: 1,
        payment_subject: 'service',
        payment_mode: 'full_prepayment'
      }
    ]
  }
};

return [{
  json: {
    idempotence_key: idempotenceKey,
    payment_body: paymentBody
  }
}];
